/**
 * HostDaddy.app — Sites content schema.
 *
 * The `sites` table in `schema.ts` is the deployment record (which Cloudflare
 * Pages project, which domain, status). This file adds the *content* layer
 * that customers edit through the Sites module: pages, blog posts, media,
 * forms, contacts, products, orders, email marketing, AI runs.
 *
 * Conventions match `schema.ts`:
 *   - IDs are text (UUIDs generated by callers via crypto.randomUUID())
 *   - All money stored as integer cents in MYR unless otherwise noted
 *   - customer_id denormalized onto every row for fast tenant filtering /
 *     simple ownership checks (each row also references site_id which itself
 *     belongs to a customer; the redundant FK is intentional)
 *   - JSON blobs stored as text — D1 has no native JSON type, parse on read
 *   - Created/updated timestamps via the shared `timestamps` helper
 */

import { sql } from 'drizzle-orm';
import { sqliteTable, text, integer, uniqueIndex, index } from 'drizzle-orm/sqlite-core';
import { customers, sites } from './schema';

// Re-declare helpers to avoid circular import of private statics.
const id = () => text('id').primaryKey();
const timestamps = {
  created_at: integer('created_at', { mode: 'timestamp' })
    .notNull()
    .default(sql`(unixepoch())`),
  updated_at: integer('updated_at', { mode: 'timestamp' })
    .notNull()
    .default(sql`(unixepoch())`),
};

// ─── Pages ───────────────────────────────────────────────────────────────────
// Each site has many pages. Content is stored as a JSON tree of sections/blocks
// matching the visual builder's data model. Rendering and AI tool-calls
// operate on this JSON.

export const sitePages = sqliteTable(
  'site_pages',
  {
    id: id(),
    customer_id: text('customer_id')
      .notNull()
      .references(() => customers.id, { onDelete: 'cascade' }),
    site_id: text('site_id')
      .notNull()
      .references(() => sites.id, { onDelete: 'cascade' }),
    slug: text('slug').notNull(), // '/', '/about', '/contact'
    title: text('title').notNull(),
    content_json: text('content_json').notNull().default('{"sections":[]}'),
    seo_title: text('seo_title'),
    seo_description: text('seo_description'),
    seo_og_image: text('seo_og_image'),
    status: text('status', { enum: ['draft', 'published', 'archived'] })
      .notNull()
      .default('draft'),
    is_home: integer('is_home', { mode: 'boolean' }).notNull().default(false),
    published_at: integer('published_at', { mode: 'timestamp' }),
    ...timestamps,
  },
  (t) => ({
    site_idx: index('site_pages_site_idx').on(t.site_id),
    customer_idx: index('site_pages_customer_idx').on(t.customer_id),
    slug_unique: uniqueIndex('site_pages_site_slug_unique').on(t.site_id, t.slug),
    status_idx: index('site_pages_status_idx').on(t.status),
  }),
);

// ─── Media library ───────────────────────────────────────────────────────────
// Backed by R2 (env.ASSETS). r2_key is the object key, file_name is what the
// user uploaded as. Optional ai_caption + alt_text generated by Workers AI.

export const siteMedia = sqliteTable(
  'site_media',
  {
    id: id(),
    customer_id: text('customer_id')
      .notNull()
      .references(() => customers.id, { onDelete: 'cascade' }),
    site_id: text('site_id')
      .notNull()
      .references(() => sites.id, { onDelete: 'cascade' }),
    r2_key: text('r2_key').notNull(),
    file_name: text('file_name').notNull(),
    mime_type: text('mime_type').notNull(),
    size_bytes: integer('size_bytes').notNull(),
    width: integer('width'),
    height: integer('height'),
    alt_text: text('alt_text'),
    ai_caption: text('ai_caption'),
    folder: text('folder'),
    ...timestamps,
  },
  (t) => ({
    site_idx: index('site_media_site_idx').on(t.site_id),
    customer_idx: index('site_media_customer_idx').on(t.customer_id),
    folder_idx: index('site_media_folder_idx').on(t.site_id, t.folder),
    r2_unique: uniqueIndex('site_media_r2_unique').on(t.r2_key),
  }),
);

// ─── Blog posts ──────────────────────────────────────────────────────────────

export const sitePosts = sqliteTable(
  'site_posts',
  {
    id: id(),
    customer_id: text('customer_id')
      .notNull()
      .references(() => customers.id, { onDelete: 'cascade' }),
    site_id: text('site_id')
      .notNull()
      .references(() => sites.id, { onDelete: 'cascade' }),
    slug: text('slug').notNull(),
    title: text('title').notNull(),
    excerpt: text('excerpt'),
    content_md: text('content_md').notNull().default(''),
    content_html: text('content_html'), // rendered cache; regenerated on save
    cover_media_id: text('cover_media_id').references(() => siteMedia.id, {
      onDelete: 'set null',
    }),
    category: text('category'),
    tags_json: text('tags_json').notNull().default('[]'),
    author_name: text('author_name').notNull(),
    status: text('status', { enum: ['draft', 'published', 'scheduled', 'archived'] })
      .notNull()
      .default('draft'),
    scheduled_for: integer('scheduled_for', { mode: 'timestamp' }),
    published_at: integer('published_at', { mode: 'timestamp' }),
    seo_title: text('seo_title'),
    seo_description: text('seo_description'),
    view_count: integer('view_count').notNull().default(0),
    ...timestamps,
  },
  (t) => ({
    site_idx: index('site_posts_site_idx').on(t.site_id),
    customer_idx: index('site_posts_customer_idx').on(t.customer_id),
    slug_unique: uniqueIndex('site_posts_site_slug_unique').on(t.site_id, t.slug),
    status_idx: index('site_posts_status_idx').on(t.status),
    published_idx: index('site_posts_published_idx').on(t.published_at),
  }),
);

