// ─── AI agent runs (audit trail) ─────────────────────────────────────────────
// Every Build-mode AI agent invocation is logged here for cost tracking,
// undo/replay, and customer transparency.

export const siteAiRuns = sqliteTable(
  'site_ai_runs',
  {
    id: id(),
    customer_id: text('customer_id')
      .notNull()
      .references(() => customers.id, { onDelete: 'cascade' }),
    site_id: text('site_id')
      .notNull()
      .references(() => sites.id, { onDelete: 'cascade' }),
    agent: text('agent', {
      enum: ['build', 'seo', 'copy', 'image', 'visitor_chat', 'email_writer'],
    }).notNull(),
    prompt: text('prompt').notNull(),
    tool_calls_json: text('tool_calls_json').notNull().default('[]'),
    result_summary: text('result_summary'),
    success: integer('success', { mode: 'boolean' }).notNull().default(true),
    duration_ms: integer('duration_ms').notNull().default(0),
    tokens_input: integer('tokens_input').notNull().default(0),
    tokens_output: integer('tokens_output').notNull().default(0),
    cost_cents: integer('cost_cents').notNull().default(0),
    model: text('model').notNull(),
    snapshot_id: text('snapshot_id'), // for undo — points to a row in site_versions
    created_at: integer('created_at', { mode: 'timestamp' })
      .notNull()
      .default(sql`(unixepoch())`),
  },
  (t) => ({
    site_idx: index('site_ai_runs_site_idx').on(t.site_id),
    customer_idx: index('site_ai_runs_customer_idx').on(t.customer_id),
    agent_idx: index('site_ai_runs_agent_idx').on(t.agent),
    created_idx: index('site_ai_runs_created_idx').on(t.created_at),
  }),
);

// ─── Version snapshots (one-click undo / restore) ────────────────────────────
// Stores a full snapshot of a page's content_json at a point in time. Used
// when the AI agent or human is about to make a destructive change.

export const siteVersions = sqliteTable(
  'site_versions',
  {
    id: id(),
    customer_id: text('customer_id')
      .notNull()
      .references(() => customers.id, { onDelete: 'cascade' }),
    site_id: text('site_id')
      .notNull()
      .references(() => sites.id, { onDelete: 'cascade' }),
    page_id: text('page_id').references(() => sitePages.id, { onDelete: 'cascade' }),
    label: text('label').notNull(), // "Before AI rewrite", "Manual save"
    actor: text('actor').notNull(), // 'customer' | 'ai:<agent>' | 'system'
    content_snapshot_json: text('content_snapshot_json').notNull(),
    created_at: integer('created_at', { mode: 'timestamp' })
      .notNull()
      .default(sql`(unixepoch())`),
  },
  (t) => ({
    site_idx: index('site_versions_site_idx').on(t.site_id),
    page_idx: index('site_versions_page_idx').on(t.page_id),
    created_idx: index('site_versions_created_idx').on(t.created_at),
  }),
);

// ─── Type exports ────────────────────────────────────────────────────────────

export type SitePage = typeof sitePages.$inferSelect;
export type NewSitePage = typeof sitePages.$inferInsert;
export type SiteMedia = typeof siteMedia.$inferSelect;
export type NewSiteMedia = typeof siteMedia.$inferInsert;
export type SitePost = typeof sitePosts.$inferSelect;
export type NewSitePost = typeof sitePosts.$inferInsert;
export type SiteForm = typeof siteForms.$inferSelect;
export type NewSiteForm = typeof siteForms.$inferInsert;
